/**
 * Solver adapter - calls Python solver via subprocess.
 *
 * This adapter provides a language-agnostic interface to the solver.
 * The solver receives JSON via stdin and returns JSON via stdout.
 *
 * Handles camelCase (TypeScript) ↔ snake_case (Python) conversion.
 */

import { spawn } from "node:child_process";
import { join } from "node:path";
import type { SolverInput, SolverOutput } from "@uptime/types";

/** Maximum recursion depth for case conversion to prevent stack overflow */
const MAX_DEPTH = 10;

export interface SolverAdapterConfig {
  /** Path to Python executable. Defaults to 'python3' */
  pythonPath?: string;
  /** Path to solver package directory */
  solverPath?: string;
  /** Timeout in milliseconds. Defaults to 120000 (2 min) */
  timeout?: number;
}

const DEFAULT_CONFIG: Required<SolverAdapterConfig> = {
  pythonPath: join(import.meta.dir, "../../../solver/.venv/bin/python"),
  solverPath: join(import.meta.dir, "../../../solver"),
  timeout: 120_000,
};

/**
 * Convert object keys from camelCase to snake_case recursively.
 * Includes depth limit to prevent stack overflow on malicious input.
 */
function toSnakeCase(obj: unknown, depth = 0): unknown {
  if (depth > MAX_DEPTH) return obj;
  if (obj === null || obj === undefined) return obj;
  if (Array.isArray(obj)) return obj.map((item) => toSnakeCase(item, depth + 1));
  if (typeof obj !== "object") return obj;

  const result: Record<string, unknown> = {};
  for (const [key, value] of Object.entries(obj as Record<string, unknown>)) {
    const snakeKey = key.replace(/([A-Z])/g, "_$1").toLowerCase();
    result[snakeKey] = toSnakeCase(value, depth + 1);
  }
  return result;
}

/**
 * Convert object keys from snake_case to camelCase recursively.
 * Includes depth limit to prevent stack overflow on malicious input.
 */
function toCamelCase(obj: unknown, depth = 0): unknown {
  if (depth > MAX_DEPTH) return obj;
  if (obj === null || obj === undefined) return obj;
  if (Array.isArray(obj)) return obj.map((item) => toCamelCase(item, depth + 1));
  if (typeof obj !== "object") return obj;

  const result: Record<string, unknown> = {};
  for (const [key, value] of Object.entries(obj as Record<string, unknown>)) {
    const camelKey = key.replace(/_([a-z])/g, (_, c) => c.toUpperCase());
    result[camelKey] = toCamelCase(value, depth + 1);
  }
  return result;
}

export class SolverAdapter {
  private config: Required<SolverAdapterConfig>;

  constructor(config: SolverAdapterConfig = {}) {
    this.config = { ...DEFAULT_CONFIG, ...config };
  }

  /**
   * Solve a maintenance scheduling problem.
   *
   * @param input - The solver input (fleet, events, constraints)
   * @returns The solver output (assignments, metrics, diagnostics)
   * @throws Error if subprocess fails or times out
   */
  async solve(input: SolverInput): Promise<SolverOutput> {
    // Convert camelCase to snake_case for Python
    const snakeCaseInput = toSnakeCase(input);
    const inputJson = JSON.stringify(snakeCaseInput);

    return new Promise((resolve, reject) => {
      const timeout = setTimeout(() => {
        proc.kill("SIGTERM");
        reject(new Error(`Solver timeout after ${this.config.timeout}ms`));
      }, this.config.timeout);

      const proc = spawn(this.config.pythonPath, ["-m", "src"], {
        cwd: this.config.solverPath,
        stdio: ["pipe", "pipe", "pipe"],
      });

      let stdout = "";
      let stderr = "";

      proc.stdout.on("data", (data) => {
        stdout += data.toString();
      });

      proc.stderr.on("data", (data) => {
        stderr += data.toString();
      });

      proc.on("close", (code) => {
        clearTimeout(timeout);

        // Always log stderr for debugging (warnings from HiGHS, etc.)
        if (stderr) {
          console.warn("[Solver stderr]", stderr);
        }

        if (code !== 0) {
          reject(
            new Error(
              `Solver exited with code ${code}: ${stderr || "No error output"}`
            )
          );
          return;
        }

        try {
          const rawOutput = JSON.parse(stdout);
          // Convert snake_case to camelCase for TypeScript
          const output = toCamelCase(rawOutput) as SolverOutput;
          resolve(output);
        } catch {
          reject(new Error(`Invalid solver output: ${stdout.slice(0, 200)}`));
        }
      });

      proc.on("error", (err) => {
        clearTimeout(timeout);
        reject(new Error(`Failed to spawn solver: ${err.message}`));
      });

      // Send input to solver
      proc.stdin.write(inputJson);
      proc.stdin.end();
    });
  }
}

/**
 * Create a new solver adapter instance.
 * Each request should create its own instance to prevent race conditions.
 */
export function createSolverAdapter(
  config?: SolverAdapterConfig
): SolverAdapter {
  return new SolverAdapter(config);
}

