/**
 * API client for communicating with the backend solver
 */

import type { SolverInput, SolverOutput } from "@uptime/types";

const API_BASE = "/api";

export interface ApiError {
  message: string;
  status: number;
}

export async function solveSchedule(input: SolverInput): Promise<SolverOutput> {
  const response = await fetch(`${API_BASE}/solver/solve`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify(input),
  });

  if (!response.ok) {
    const error = await response.json().catch(() => ({ message: "Unknown error" }));
    throw new Error(error.message || `HTTP ${response.status}`);
  }

  return response.json();
}

export async function checkSolverHealth(): Promise<{ status: string; solver: string }> {
  const response = await fetch(`${API_BASE}/solver/health`);

  if (!response.ok) {
    throw new Error(`Solver unavailable: HTTP ${response.status}`);
  }

  return response.json();
}

import { useState, useCallback } from "react";
import {
  Card,
  Elevation,
  Button,
  Intent,
  FormGroup,
  Slider,
  HTMLSelect,
  Spinner,
  Callout,
  Tag,
  ProgressBar,
} from "@blueprintjs/core";
import type { SolverOutput } from "@uptime/types";
import { createSolverInput } from "../lib/demo-data";
import { solveSchedule } from "../lib/api";

export function WhatIfSimulator() {
  const [isRunning, setIsRunning] = useState(false);
  const [result, setResult] = useState<SolverOutput | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Form state
  const [capacity, setCapacity] = useState(5200);
  const [horizon, setHorizon] = useState(13);
  const [fleetSize, setFleetSize] = useState(128);

  const runSimulation = useCallback(async () => {
    setIsRunning(true);
    setError(null);
    setResult(null);

    try {
      const input = createSolverInput(fleetSize, horizon, capacity);
      const output = await solveSchedule(input);
      setResult(output);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Unknown error");
    } finally {
      setIsRunning(false);
    }
  }, [capacity, horizon, fleetSize]);

  const resetForm = () => {
    setCapacity(5200);
    setHorizon(13);
    setFleetSize(128);
    setResult(null);
    setError(null);
  };

  return (
    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "24px" }}>
      <Card elevation={Elevation.TWO}>
        <h3 style={{ marginTop: 0 }}>Scenario Parameters</h3>

        <FormGroup label="Planning Horizon" labelInfo="(weeks)">
          <HTMLSelect
            value={horizon}
            onChange={(e) => setHorizon(parseInt(e.target.value))}
            fill
          >
            <option value={13}>13 weeks (Quarter)</option>
            <option value={26}>26 weeks (Half Year)</option>
            <option value={52}>52 weeks (Full Year)</option>
          </HTMLSelect>
        </FormGroup>

        <FormGroup
          label="Weekly Capacity"
          labelInfo={`${capacity.toLocaleString()} man-hours`}
        >
          <Slider
            min={3000}
            max={8000}
            stepSize={100}
            value={capacity}
            onChange={setCapacity}
            labelStepSize={1000}
          />
        </FormGroup>

        <FormGroup label="Fleet Size">
          <HTMLSelect
            value={fleetSize}
            onChange={(e) => setFleetSize(parseInt(e.target.value))}
            fill
          >
            <option value={128}>Full Fleet (128)</option>
            <option value={64}>Medium Fleet (64)</option>
            <option value={20}>Small Fleet (20)</option>
            <option value={10}>Test Fleet (10)</option>
          </HTMLSelect>
        </FormGroup>

        <div style={{ display: "flex", gap: "8px", marginTop: "24px" }}>
          <Button onClick={resetForm}>Reset</Button>
          <Button
            intent={Intent.PRIMARY}
            loading={isRunning}
            onClick={runSimulation}
          >
            {isRunning ? "Running Solver..." : "Run Simulation"}
          </Button>
        </div>
      </Card>

      <Card elevation={Elevation.TWO}>
        <h3 style={{ marginTop: 0 }}>Results</h3>

        {isRunning && (
          <div style={{ textAlign: "center", padding: "40px 0" }}>
            <Spinner size={40} />
            <p style={{ color: "#5f6b7c", marginTop: "16px" }}>
              Running HiGHS MIP solver...
            </p>
          </div>
        )}

        {error && (
          <Callout intent={Intent.DANGER} title="Solver Error">
            {error}
          </Callout>
        )}

        {result && !isRunning && (
          <div>
            <Callout
              intent={
                result.status === "OPTIMAL"
                  ? Intent.SUCCESS
                  : result.status === "FEASIBLE"
                  ? Intent.PRIMARY
                  : Intent.WARNING
              }
              style={{ marginBottom: "16px" }}
            >
              <strong>{result.status}</strong> solution found in{" "}
              {result.diagnostics.solveTimeMs.toFixed(0)}ms
            </Callout>

            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "16px" }}>
              <div>
                <div style={{ color: "#5f6b7c", fontSize: "12px" }}>Status</div>
                <Tag
                  large
                  intent={
                    result.status === "OPTIMAL"
                      ? Intent.SUCCESS
                      : result.status === "FEASIBLE"
                      ? Intent.PRIMARY
                      : Intent.DANGER
                  }
                >
                  {result.status}
                </Tag>
              </div>

              <div>
                <div style={{ color: "#5f6b7c", fontSize: "12px" }}>Solve Time</div>
                <div style={{ fontSize: "18px", fontWeight: 500 }}>
                  {result.diagnostics.solveTimeMs.toFixed(2)}ms
                </div>
              </div>

              <div>
                <div style={{ color: "#5f6b7c", fontSize: "12px" }}>Events Scheduled</div>
                <div style={{ fontSize: "18px", fontWeight: 500 }}>
                  {result.solution?.assignments.length || 0}
                </div>
              </div>

              <div>
                <div style={{ color: "#5f6b7c", fontSize: "12px" }}>Planning Horizon</div>
                <div style={{ fontSize: "18px", fontWeight: 500 }}>
                  {horizon} weeks
                </div>
              </div>
            </div>

            {result.metrics && (
              <div style={{ marginTop: "24px" }}>
                <h4>Key Metrics</h4>

                <div style={{ marginBottom: "12px" }}>
                  <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "4px" }}>
                    <span>Peak Workload</span>
                    <span>{result.metrics.peakWorkload.toLocaleString()} man-hours</span>
                  </div>
                  <ProgressBar
                    value={result.metrics.peakWorkload / capacity}
                    intent={
                      result.metrics.peakWorkload / capacity > 0.9
                        ? Intent.DANGER
                        : result.metrics.peakWorkload / capacity > 0.7
                        ? Intent.WARNING
                        : Intent.SUCCESS
                    }
                  />
                </div>

                <div style={{ marginBottom: "12px" }}>
                  <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "4px" }}>
                    <span>Average Workload</span>
                    <span>{result.metrics.averageWorkload.toLocaleString()} man-hours</span>
                  </div>
                  <ProgressBar
                    value={result.metrics.averageWorkload / capacity}
                    intent={Intent.PRIMARY}
                  />
                </div>

                <div style={{ marginBottom: "12px" }}>
                  <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "4px" }}>
                    <span>Compliance Rate</span>
                    <span>{(result.metrics.complianceRate * 100).toFixed(1)}%</span>
                  </div>
                  <ProgressBar
                    value={result.metrics.complianceRate}
                    intent={
                      result.metrics.complianceRate > 0.9
                        ? Intent.SUCCESS
                        : result.metrics.complianceRate > 0.7
                        ? Intent.WARNING
                        : Intent.DANGER
                    }
                  />
                </div>

                <div>
                  <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "4px" }}>
                    <span>Workload Variance (CV)</span>
                    <span>{(result.metrics.workloadCv * 100).toFixed(1)}%</span>
                  </div>
                  <ProgressBar
                    value={Math.min(result.metrics.workloadCv, 1)}
                    intent={
                      result.metrics.workloadCv < 0.3
                        ? Intent.SUCCESS
                        : result.metrics.workloadCv < 0.5
                        ? Intent.WARNING
                        : Intent.DANGER
                    }
                  />
                </div>
              </div>
            )}
          </div>
        )}

        {!isRunning && !error && !result && (
          <div style={{ textAlign: "center", padding: "40px 0", color: "#5f6b7c" }}>
            <p>Configure parameters and click "Run Simulation"</p>
          </div>
        )}
      </Card>
    </div>
  );
}

